import{_ as o,o as t,c as a,au as r}from"./chunks/framework.Bpqx6pAq.js";const p=JSON.parse('{"title":"Query hooks","description":"","frontmatter":{},"headers":[],"relativePath":"api/map/hooks/hooks.query.md","filePath":"api/map/hooks/hooks.query.md"}'),d={name:"api/map/hooks/hooks.query.md"};function s(c,e,i,n,l,h){return t(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="query-hooks" tabindex="-1">Query hooks <a class="header-anchor" href="#query-hooks" aria-label="Permalink to &quot;Query hooks&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Hooks for marshalling spatial and temporal query parameters into the MongoDB format expected by the features service, and for transforming service results into GeoJSON.</p><h2 id="functions" tabindex="-1">Functions <a class="header-anchor" href="#functions" aria-label="Permalink to &quot;Functions&quot;">​</a></h2><h3 id="marshallgeometryquery-hook" tabindex="-1"><code>marshallGeometryQuery(hook)</code> <a class="header-anchor" href="#marshallgeometryquery-hook" aria-label="Permalink to &quot;`marshallGeometryQuery(hook)`&quot;">​</a></h3><p>Converts the <code>geometry</code> field in <code>hook.params.query</code> from its client/server-side representation into the MongoDB-compatible format via <code>marshallGeometry</code>. No-op when the query or geometry field is absent.</p><hr><h3 id="marshallgeojsonquery-hook" tabindex="-1"><code>marshallGeoJsonQuery(hook)</code> <a class="header-anchor" href="#marshallgeojsonquery-hook" aria-label="Permalink to &quot;`marshallGeoJsonQuery(hook)`&quot;">​</a></h3><p>Detects the <code>geoJson: true</code> shortcut in <code>hook.params.query</code>, removes it from the query, and sets <code>hook.params.asGeoJson = true</code> to signal downstream hooks (such as <code>asGeoJson</code>) to convert results to GeoJSON.</p><hr><h3 id="marshallspatialquery-hook" tabindex="-1"><code>marshallSpatialQuery(hook)</code> <a class="header-anchor" href="#marshallspatialquery-hook" aria-label="Permalink to &quot;`marshallSpatialQuery(hook)`&quot;">​</a></h3><p>Converts spatial shortcut parameters in <code>hook.params.query</code> into their MongoDB geospatial operator equivalents, then calls <code>marshallGeoJsonQuery</code>.</p><p>Supported shortcuts:</p><table tabindex="0"><thead><tr><th>Shortcut parameters</th><th>MongoDB translation</th></tr></thead><tbody><tr><td><code>geometry</code></td><td><code>marshallGeometry(query.geometry)</code></td></tr><tr><td><code>centerLon</code>/<code>longitude</code> + <code>centerLat</code>/<code>latitude</code> + <code>distance</code></td><td><code>geometry.$geoWithin.$centerSphere</code> (proximity query). Uses <code>$geoNear</code> instead when <code>$aggregate</code> is present.</td></tr><tr><td><code>south</code> + <code>north</code> + <code>west</code> + <code>east</code></td><td><code>geometry.$geoIntersects</code> on a bounding-box polygon. Splits bounding boxes wider than 180° into two halves to work around MongoDB limitations. Supports arrays of bboxes via <code>$or</code>.</td></tr><tr><td><code>longitude</code> + <code>latitude</code> (without <code>distance</code>)</td><td><code>geometry.$geoIntersects</code> on a Point (location-contains query)</td></tr></tbody></table><hr><h3 id="asgeojson-options" tabindex="-1"><code>asGeoJson(options?)</code> <a class="header-anchor" href="#asgeojson-options" aria-label="Permalink to &quot;`asGeoJson(options?)`&quot;">​</a></h3><blockquote><p>Returns a hook function. To be used as an <code>after</code> hook.</p></blockquote><p>Converts the hook result (flat feature records with coordinate fields) into a <a href="https://tools.ietf.org/html/rfc7946" target="_blank" rel="noreferrer">GeoJSON</a> FeatureCollection or array of Features. Only runs when <code>hook.params.asGeoJson</code> is <code>true</code> or <code>options.force</code> is set. No-op if the result is already a FeatureCollection, or if <code>$distinct</code>/<code>$aggregation</code> queries are detected.</p><h4 id="options" tabindex="-1">Options <a class="header-anchor" href="#options" aria-label="Permalink to &quot;Options&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Option</th><th>Type</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>force</code></td><td>boolean</td><td><code>false</code></td><td>Run regardless of <code>hook.params.asGeoJson</code></td></tr><tr><td><code>longitudeProperty</code></td><td>string</td><td><code>&#39;longitude&#39;</code></td><td>Field name for longitude</td></tr><tr><td><code>latitudeProperty</code></td><td>string</td><td><code>&#39;latitude&#39;</code></td><td>Field name for latitude</td></tr><tr><td><code>altitudeProperty</code></td><td>string</td><td><code>&#39;altitude&#39;</code></td><td>Field name for altitude</td></tr><tr><td><code>geometryProperty</code></td><td>string</td><td><code>&#39;geometry&#39;</code></td><td>Field name for an existing geometry object</td></tr><tr><td><code>allowNullGeometries</code></td><td>boolean</td><td><code>false</code></td><td>Include items without coordinate fields (geometry will be <code>null</code>)</td></tr><tr><td><code>pick</code></td><td>Array</td><td>—</td><td>Properties to keep on each item (Lodash pick)</td></tr><tr><td><code>omit</code></td><td>Array</td><td>—</td><td>Properties to remove from each item (Lodash omit)</td></tr><tr><td><code>properties</code></td><td><code>true</code> | Array</td><td>—</td><td><code>true</code> moves all non-geometry fields into <code>feature.properties</code>. An array of <code>{ from, to?, delete? }</code> mappings moves specific fields.</td></tr><tr><td><code>asFeatureCollection</code></td><td>boolean</td><td><code>true</code></td><td>Wrap features in a <code>FeatureCollection</code> object</td></tr><tr><td><code>dataPath</code></td><td>string</td><td><code>&#39;result&#39;</code></td><td>Lodash path to read/write the result on the hook</td></tr></tbody></table><p>Pagination metadata (<code>total</code>, <code>skip</code>, <code>limit</code>) is preserved when the original result is paginated.</p><hr><h3 id="aggregatefeaturesquery-hook" tabindex="-1"><code>aggregateFeaturesQuery(hook)</code> <a class="header-anchor" href="#aggregatefeaturesquery-hook" aria-label="Permalink to &quot;`aggregateFeaturesQuery(hook)`&quot;">​</a></h3><blockquote><p>To be used as a <code>before</code> hook.</p></blockquote><p>Constructs and executes a MongoDB aggregation pipeline when <code>hook.params.query.$aggregate</code> is present, bypassing the normal service database call by setting <code>hook.result</code> directly.</p><p>This hook supports <a href="./../services.html#time-based-feature-aggregation">time-based feature aggregation</a>: for each variable listed in <code>$aggregate</code>, it runs a separate pipeline stage that groups features by the ID specified in <code>$groupBy</code>, collecting time arrays and variable value arrays. Results from all elements are merged by feature ID.</p><p>Key query parameters consumed:</p><table tabindex="0"><thead><tr><th>Parameter</th><th>Description</th></tr></thead><tbody><tr><td><code>$aggregate</code></td><td>Array of property names (or <code>&#39;geometry&#39;</code>) to aggregate across time</td></tr><tr><td><code>$groupBy</code></td><td>Field name or array of field names to group features by</td></tr><tr><td><code>$group</code></td><td>Additional MongoDB <code>$group</code> accumulator expressions (validated against a safe-operator allowlist)</td></tr><tr><td><code>$geoNear</code></td><td>Optional geospatial stage injected before the <code>$match</code> step</td></tr><tr><td><code>$sort</code></td><td>Sort overrides applied within the aggregation pipeline</td></tr><tr><td><code>$limit: 1</code></td><td>Shortcut to keep only the first/last time point without full aggregation</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>To prevent injection attacks, <code>$group</code> expressions are validated against an allowlist of safe MongoDB accumulator and expression operators. Operators such as <code>$accumulator</code>, <code>$function</code>, and <code>$where</code> are explicitly forbidden.</p></div>',29)])])}const g=o(d,[["render",s]]);export{p as __pageData,g as default};
